--
-- Table structure for table `EQP_MAINT_HIS`
--

DROP TABLE IF EXISTS `EQP_MAINT_HIS`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `EQP_MAINT_HIS` (
  `MAINT_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '정비ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `EQUIPMENT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '설비코드',
  `MAINT_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '정비번호',
  `MAINT_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '정비유형',
  `MAINT_DT` date NOT NULL COMMENT '정비일자',
  `MAINT_PLAN_ID` bigint DEFAULT NULL COMMENT '정비계획ID',
  `DOWNTIME_ID` bigint DEFAULT NULL COMMENT '비가동ID',
  `START_DTM` datetime NOT NULL COMMENT '시작일시',
  `END_DTM` datetime DEFAULT NULL COMMENT '종료일시',
  `MAINT_TIME` decimal(10,2) DEFAULT NULL COMMENT '정비시간(분)',
  `MAINT_WORKER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '정비자ID',
  `MAINT_TEAM` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '정비팀',
  `MAINT_CONTENT` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '정비내용',
  `SYMPTOM` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고장증상',
  `CAUSE` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고장원인',
  `ACTION` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '조치내용',
  `PART_REPLACED` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '교체부품',
  `PART_COST` decimal(18,2) DEFAULT '0.00' COMMENT '부품비용',
  `LABOR_COST` decimal(18,2) DEFAULT '0.00' COMMENT '인건비',
  `OTHER_COST` decimal(18,2) DEFAULT '0.00' COMMENT '기타비용',
  `MAINT_COST` decimal(18,2) GENERATED ALWAYS AS (((coalesce(`PART_COST`,0) + coalesce(`LABOR_COST`,0)) + coalesce(`OTHER_COST`,0))) STORED COMMENT '총정비비용',
  `MAINT_RESULT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '진행' COMMENT '정비결과',
  `NEXT_MAINT_DT` date DEFAULT NULL COMMENT '다음정비예정일',
  `MAINT_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`MAINT_ID`),
  UNIQUE KEY `UK_EQP_MAINT_HIS` (`MAINT_NO`),
  KEY `FK_EQP_MAINT_HIS_DT` (`DOWNTIME_ID`),
  KEY `IDX_EQP_MAINT_HIS_01` (`EQUIPMENT_CD`,`MAINT_DT`),
  KEY `IDX_EQP_MAINT_HIS_02` (`PLANT_CD`,`MAINT_DT`),
  KEY `IDX_EQP_MAINT_HIS_03` (`MAINT_TYPE`),
  KEY `IDX_EQP_MAINT_HIS_04` (`MAINT_PLAN_ID`),
  CONSTRAINT `FK_EQP_MAINT_HIS_DT` FOREIGN KEY (`DOWNTIME_ID`) REFERENCES `EQP_DOWNTIME` (`DOWNTIME_ID`),
  CONSTRAINT `FK_EQP_MAINT_HIS_EQP` FOREIGN KEY (`EQUIPMENT_CD`) REFERENCES `MST_EQUIPMENT` (`EQUIPMENT_CD`),
  CONSTRAINT `FK_EQP_MAINT_HIS_PLAN` FOREIGN KEY (`MAINT_PLAN_ID`) REFERENCES `EQP_MAINT_PLAN` (`MAINT_PLAN_ID`),
  CONSTRAINT `FK_EQP_MAINT_HIS_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='정비이력';
