--
-- Table structure for table `EQP_MAINT_PLAN`
--

DROP TABLE IF EXISTS `EQP_MAINT_PLAN`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `EQP_MAINT_PLAN` (
  `MAINT_PLAN_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '정비계획ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `EQUIPMENT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '설비코드',
  `MAINT_PLAN_NM` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '정비계획명',
  `MAINT_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '정비유형',
  `CYCLE_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '주기유형',
  `CYCLE_VALUE` int NOT NULL COMMENT '주기값',
  `CYCLE_UNIT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '일' COMMENT '주기단위',
  `BASE_DT` date DEFAULT NULL COMMENT '기준일',
  `LAST_MAINT_DT` date DEFAULT NULL COMMENT '최종정비일',
  `NEXT_MAINT_DT` date DEFAULT NULL COMMENT '다음정비예정일',
  `LEAD_TIME` int DEFAULT '0' COMMENT '사전알림(일)',
  `EST_MAINT_TIME` decimal(10,2) DEFAULT NULL COMMENT '예상정비시간(분)',
  `EST_COST` decimal(18,2) DEFAULT NULL COMMENT '예상비용',
  `MAINT_CHECKLIST` text COLLATE utf8mb4_general_ci COMMENT '정비체크리스트',
  `MAINT_CONTENT` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '정비내용',
  `MANAGER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '담당자ID',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '사용여부',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`MAINT_PLAN_ID`),
  KEY `FK_EQP_MAINT_PLAN_PLANT` (`PLANT_CD`),
  KEY `IDX_EQP_MAINT_PLAN_01` (`EQUIPMENT_CD`),
  KEY `IDX_EQP_MAINT_PLAN_02` (`NEXT_MAINT_DT`),
  CONSTRAINT `FK_EQP_MAINT_PLAN_EQP` FOREIGN KEY (`EQUIPMENT_CD`) REFERENCES `MST_EQUIPMENT` (`EQUIPMENT_CD`),
  CONSTRAINT `FK_EQP_MAINT_PLAN_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='정비계획';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `EQP_MAINT_PLAN`
--

LOCK TABLES `EQP_MAINT_PLAN` WRITE;
/*!40000 ALTER TABLE `EQP_MAINT_PLAN` DISABLE KEYS */;
