--
-- Table structure for table `EQP_OPER_STATUS`
--

DROP TABLE IF EXISTS `EQP_OPER_STATUS`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `EQP_OPER_STATUS` (
  `OPER_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '가동ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `EQUIPMENT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '설비코드',
  `OPER_DT` date NOT NULL COMMENT '가동일자',
  `SHIFT` varchar(10) COLLATE utf8mb4_general_ci NOT NULL COMMENT '근무조',
  `OPER_STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '가동상태',
  `START_DTM` datetime NOT NULL COMMENT '시작일시',
  `END_DTM` datetime DEFAULT NULL COMMENT '종료일시',
  `OPER_TIME` decimal(10,2) DEFAULT NULL COMMENT '가동시간(분)',
  `WO_ID` bigint DEFAULT NULL COMMENT '작업지시ID',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '품목코드',
  `PROD_QTY` decimal(15,3) DEFAULT NULL COMMENT '생산수량',
  `WORKER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '작업자ID',
  `OPER_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`OPER_ID`),
  KEY `FK_EQP_OPER_ITEM` (`ITEM_CD`),
  KEY `FK_EQP_OPER_WORKER` (`WORKER_ID`),
  KEY `IDX_EQP_OPER_STATUS_01` (`EQUIPMENT_CD`,`OPER_DT`),
  KEY `IDX_EQP_OPER_STATUS_02` (`PLANT_CD`,`OPER_DT`),
  KEY `IDX_EQP_OPER_STATUS_03` (`WO_ID`),
  KEY `IDX_EQP_OPER_STATUS_04` (`OPER_STATUS`),
  CONSTRAINT `FK_EQP_OPER_EQP` FOREIGN KEY (`EQUIPMENT_CD`) REFERENCES `MST_EQUIPMENT` (`EQUIPMENT_CD`),
  CONSTRAINT `FK_EQP_OPER_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_EQP_OPER_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_EQP_OPER_WO` FOREIGN KEY (`WO_ID`) REFERENCES `PLN_WORK_ORDER` (`WO_ID`),
  CONSTRAINT `FK_EQP_OPER_WORKER` FOREIGN KEY (`WORKER_ID`) REFERENCES `MST_WORKER` (`WORKER_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설비가동현황';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `EQP_OPER_STATUS`
--

LOCK TABLES `EQP_OPER_STATUS` WRITE;
