DROP TABLE IF EXISTS `EQP_PARAMETER`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `EQP_PARAMETER` (
  `PARAM_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '파라미터ID',
  `EQUIPMENT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '설비코드',
  `PARAM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '파라미터코드',
  `PARAM_NM` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '파라미터명',
  `PARAM_TYPE` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '파라미터유형',
  `DATA_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'NUMBER' COMMENT '데이터유형',
  `UNIT` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '단위',
  `LSL` decimal(15,5) DEFAULT NULL COMMENT '하한값',
  `USL` decimal(15,5) DEFAULT NULL COMMENT '상한값',
  `TARGET_VALUE` decimal(15,5) DEFAULT NULL COMMENT '목표값',
  `CURRENT_VALUE` decimal(15,5) DEFAULT NULL COMMENT '현재값',
  `LAST_UPDATE_DTM` datetime DEFAULT NULL COMMENT '최종갱신일시',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '사용여부',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`PARAM_ID`),
  UNIQUE KEY `UK_EQP_PARAMETER` (`EQUIPMENT_CD`,`PARAM_CD`),
  KEY `IDX_EQP_PARAMETER_01` (`EQUIPMENT_CD`),
  CONSTRAINT `FK_EQP_PARAM_EQP` FOREIGN KEY (`EQUIPMENT_CD`) REFERENCES `MST_EQUIPMENT` (`EQUIPMENT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설비파라미터';
/*!40101 SET character_set_client = @saved_cs_client */;

