  KEY `IDX_EQP_PARAM_HIS_01` (`PARAM_ID`,`MEASURE_DTM`),
  KEY `IDX_EQP_PARAM_HIS_02` (`EQUIPMENT_CD`,`MEASURE_DTM`),
