  CONSTRAINT `FK_EQP_PARAM_HIS_PARAM` FOREIGN KEY (`PARAM_ID`) REFERENCES `EQP_PARAMETER` (`PARAM_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=44 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설비파라미터이력';
