  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`SPARE_PART_ID`),
  UNIQUE KEY `UK_EQP_SPARE_PART` (`EQUIPMENT_CD`,`PART_CD`),
  KEY `IDX_EQP_SPARE_PART_01` (`EQUIPMENT_CD`),
  CONSTRAINT `FK_EQP_SPARE_PART_EQP` FOREIGN KEY (`EQUIPMENT_CD`) REFERENCES `MST_EQUIPMENT` (`EQUIPMENT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=26 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설비부품';
