CREATE TABLE `INV_ISSUE_PLAN` (
  `ISSUE_PLAN_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '출고예정ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `ISSUE_PLAN_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '출고예정번호',
  `PLAN_DT` date NOT NULL COMMENT '예정일자',
  `ISSUE_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '출고유형',
  `CUSTOMER_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고객코드',
  `ORDER_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '주문번호',
  `WO_ID` bigint DEFAULT NULL COMMENT '작업지시ID',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `PLAN_QTY` decimal(15,3) NOT NULL COMMENT '예정수량',
  `ISSUE_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '출고수량',
  `WAREHOUSE_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '출고창고',
  `STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '예정' COMMENT '상태',
  `PLAN_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`ISSUE_PLAN_ID`),
  UNIQUE KEY `UK_INV_ISSUE_PLAN` (`ISSUE_PLAN_NO`),
  KEY `FK_INV_ISSUE_PLAN_WH` (`WAREHOUSE_CD`),
  KEY `IDX_INV_ISSUE_PLAN_01` (`PLANT_CD`,`PLAN_DT`),
  KEY `IDX_INV_ISSUE_PLAN_02` (`WO_ID`),
  KEY `IDX_INV_ISSUE_PLAN_03` (`ITEM_CD`),
  CONSTRAINT `FK_INV_ISSUE_PLAN_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_INV_ISSUE_PLAN_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_INV_ISSUE_PLAN_WH` FOREIGN KEY (`WAREHOUSE_CD`) REFERENCES `MST_WAREHOUSE` (`WAREHOUSE_CD`),
  CONSTRAINT `FK_INV_ISSUE_PLAN_WO` FOREIGN KEY (`WO_ID`) REFERENCES `PLN_WORK_ORDER` (`WO_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='출고예정';
