--
-- Table structure for table `INV_LOT_TRACE`
--

DROP TABLE IF EXISTS `INV_LOT_TRACE`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `INV_LOT_TRACE` (
  `TRACE_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '추적ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT 'LOT번호',
  `PARENT_LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '상위LOT번호',
  `CHILD_LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '하위LOT번호',
  `TRACE_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '추적유형',
  `TRACE_LEVEL` int NOT NULL DEFAULT '1' COMMENT '추적레벨',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `PROCESS_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '공정코드',
  `WO_ID` bigint DEFAULT NULL COMMENT '작업지시ID',
  `RESULT_ID` bigint DEFAULT NULL COMMENT '작업실적ID',
  `TRACE_DTM` datetime NOT NULL COMMENT '추적일시',
  `TRACE_QTY` decimal(15,3) DEFAULT NULL COMMENT '추적수량',
  `TRACE_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  PRIMARY KEY (`TRACE_ID`),
  KEY `FK_INV_LOT_TRACE_PLANT` (`PLANT_CD`),
  KEY `FK_INV_LOT_TRACE_WO` (`WO_ID`),
  KEY `IDX_INV_LOT_TRACE_01` (`LOT_NO`),
  KEY `IDX_INV_LOT_TRACE_02` (`PARENT_LOT_NO`),
  KEY `IDX_INV_LOT_TRACE_03` (`CHILD_LOT_NO`),
  KEY `IDX_INV_LOT_TRACE_04` (`ITEM_CD`),
  CONSTRAINT `FK_INV_LOT_TRACE_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_INV_LOT_TRACE_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_INV_LOT_TRACE_WO` FOREIGN KEY (`WO_ID`) REFERENCES `PLN_WORK_ORDER` (`WO_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='LOT추적이력';
/*!40101 SET character_set_client = @saved_cs_client */;

