--
-- Table structure for table `INV_RECEIVE_PLAN`
--

DROP TABLE IF EXISTS `INV_RECEIVE_PLAN`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `INV_RECEIVE_PLAN` (
  `RECEIVE_PLAN_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '입고예정ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `RECEIVE_PLAN_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '입고예정번호',
  `PLAN_DT` date NOT NULL COMMENT '예정일자',
  `RECEIVE_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '입고유형',
  `VENDOR_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '거래처코드',
  `PO_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '발주번호',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `PLAN_QTY` decimal(15,3) NOT NULL COMMENT '예정수량',
  `RECEIVE_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '입고수량',
  `WAREHOUSE_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '입고창고',
  `STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '예정' COMMENT '상태',
  `PLAN_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
