  CONSTRAINT `FK_MCS_LOC_TRANS_STOCK` FOREIGN KEY (`LOC_STOCK_ID`) REFERENCES `MCS_LOCATION_STOCK` (`LOC_STOCK_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='MCS 로케이션재고이력';
