--
-- Table structure for table `MST_ITEM`
--

DROP TABLE IF EXISTS `MST_ITEM`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `MST_ITEM` (
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `ITEM_NM` varchar(200) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목명',
  `ITEM_EN_NM` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '품목영문명',
  `ITEM_SPEC` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '규격',
  `ITEM_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목유형',
  `ITEM_GRP` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '품목그룹',
  `ITEM_CLASS` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '품목분류',
  `UNIT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '기본단위',
  `SUB_UNIT` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '보조단위',
  `UNIT_CONV_RATE` decimal(15,5) DEFAULT NULL COMMENT '단위환산율',
  `SAFETY_STOCK_QTY` decimal(15,3) DEFAULT NULL COMMENT '안전재고수량',
  `MIN_ORDER_QTY` decimal(15,3) DEFAULT NULL COMMENT '최소발주수량',
  `LEAD_TIME` int DEFAULT NULL COMMENT '리드타임(일)',
  `LOT_SIZE` decimal(15,3) DEFAULT NULL COMMENT 'LOT크기',
  `SHELF_LIFE` int DEFAULT NULL COMMENT '유효기간(일)',
  `WEIGHT` decimal(15,5) DEFAULT NULL COMMENT '중량',
  `WEIGHT_UNIT` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '중량단위',
  `VOLUME` decimal(15,5) DEFAULT NULL COMMENT '부피',
  `VOLUME_UNIT` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '부피단위',
  `PURCHASE_PRICE` decimal(18,2) DEFAULT NULL COMMENT '구매단가',
  `SALE_PRICE` decimal(18,2) DEFAULT NULL COMMENT '판매단가',
  `STANDARD_COST` decimal(18,2) DEFAULT NULL COMMENT '표준원가',
  `VENDOR_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '주거래처코드',
  `INSPECT_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '검사여부',
  `LOT_MANAGE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT 'LOT관리여부',
  `SERIAL_MANAGE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'N' COMMENT '시리얼관리여부',
  `DRAWING_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '도면번호',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '사용여부',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`ITEM_CD`),
  KEY `FK_MST_ITEM_VENDOR` (`VENDOR_CD`),
  KEY `IDX_MST_ITEM_01` (`PLANT_CD`,`ITEM_TYPE`),
  KEY `IDX_MST_ITEM_02` (`ITEM_NM`),
  KEY `IDX_MST_ITEM_03` (`ITEM_GRP`),
  CONSTRAINT `FK_MST_ITEM_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_MST_ITEM_VENDOR` FOREIGN KEY (`VENDOR_CD`) REFERENCES `MST_VENDOR` (`VENDOR_CD`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='품목정보';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `MST_ITEM`
--

LOCK TABLES `MST_ITEM` WRITE;
/*!40000 ALTER TABLE `MST_ITEM` DISABLE KEYS */;
