--
-- Table structure for table `MST_PLANT`
--

DROP TABLE IF EXISTS `MST_PLANT`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `MST_PLANT` (
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `COMPANY_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '회사코드',
  `PLANT_NM` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장명',
  `PLANT_TYPE` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '공장유형',
  `ADDR` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '주소',
  `TEL_NO` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '전화번호',
  `FAX_NO` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '팩스번호',
  `MANAGER_NM` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '담당자명',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '사용여부',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`PLANT_CD`),
  KEY `IDX_MST_PLANT_01` (`COMPANY_CD`,`USE_YN`),
  KEY `IDX_MST_PLANT_02` (`PLANT_NM`),
  CONSTRAINT `FK_MST_PLANT_COMPANY` FOREIGN KEY (`COMPANY_CD`) REFERENCES `MST_COMPANY` (`COMPANY_CD`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='공장정보';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `MST_PLANT`
--

