-- Table structure for table `PLN_PROD_PLAN`
--

DROP TABLE IF EXISTS `PLN_PROD_PLAN`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PLN_PROD_PLAN` (
  `PLAN_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '계획ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `PLAN_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '계획번호',
  `PLAN_DT` date NOT NULL COMMENT '계획일자',
  `PLAN_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '계획유형',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `PLAN_QTY` decimal(15,3) NOT NULL COMMENT '계획수량',
  `PLAN_START_DT` date NOT NULL COMMENT '계획시작일',
  `PLAN_END_DT` date NOT NULL COMMENT '계획종료일',
  `PRIORITY` int DEFAULT '5' COMMENT '우선순위',
  `ORDER_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수주번호',
  `CUSTOMER_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고객코드',
  `CUSTOMER_NM` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고객명',
  `DELIVERY_DT` date DEFAULT NULL COMMENT '납기일',
  `PLAN_STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '계획' COMMENT '계획상태',
  `RESULT_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '실적수량',
  `PLAN_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `APPROVE_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '승인자ID',
  `APPROVE_DTM` datetime DEFAULT NULL COMMENT '승인일시',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`PLAN_ID`),
  UNIQUE KEY `UK_PLN_PROD_PLAN` (`PLAN_NO`),
  KEY `IDX_PLN_PROD_PLAN_01` (`PLANT_CD`,`PLAN_DT`),
  KEY `IDX_PLN_PROD_PLAN_02` (`ITEM_CD`),
  KEY `IDX_PLN_PROD_PLAN_03` (`PLAN_STATUS`),
  CONSTRAINT `FK_PLN_PROD_PLAN_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_PLN_PROD_PLAN_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='생산계획';
/*!40101 SET character_set_client = @saved_cs_client */;

