--
-- Table structure for table `PLN_WORK_ORDER`
--

DROP TABLE IF EXISTS `PLN_WORK_ORDER`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PLN_WORK_ORDER` (
  `WO_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '작업지시ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `WO_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '작업지시번호',
  `PLAN_ID` bigint DEFAULT NULL COMMENT '계획ID',
  `WO_DT` date NOT NULL COMMENT '작업지시일',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `WO_QTY` decimal(15,3) NOT NULL COMMENT '지시수량',
  `WORKCENTER_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '작업장코드',
  `EQUIPMENT_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '설비코드',
  `WORKER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '작업자ID',
  `PLAN_START_DTM` datetime NOT NULL COMMENT '계획시작일시',
  `PLAN_END_DTM` datetime NOT NULL COMMENT '계획종료일시',
  `ACTUAL_START_DTM` datetime DEFAULT NULL COMMENT '실제시작일시',
  `ACTUAL_END_DTM` datetime DEFAULT NULL COMMENT '실제종료일시',
  `GOOD_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '양품수량',
  `DEFECT_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '불량수량',
  `WO_STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '대기' COMMENT '작업상태',
  `PRIORITY` int DEFAULT '5' COMMENT '우선순위',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `PARENT_WO_ID` bigint DEFAULT NULL COMMENT '상위작업지시ID',
  `ORDER_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수주번호',
  `DELIVERY_DT` date DEFAULT NULL COMMENT '납기일',
  `WO_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`WO_ID`),
  UNIQUE KEY `UK_PLN_WORK_ORDER` (`WO_NO`),
  KEY `FK_PLN_WO_EQP` (`EQUIPMENT_CD`),
  KEY `FK_PLN_WO_WORKER` (`WORKER_ID`),
  KEY `IDX_PLN_WORK_ORDER_01` (`PLANT_CD`,`WO_DT`,`WO_STATUS`),
  KEY `IDX_PLN_WORK_ORDER_02` (`ITEM_CD`),
  KEY `IDX_PLN_WORK_ORDER_03` (`LOT_NO`),
  KEY `IDX_PLN_WORK_ORDER_04` (`WORKCENTER_CD`),
  KEY `IDX_PLN_WORK_ORDER_05` (`PLAN_ID`),
  CONSTRAINT `FK_PLN_WO_EQP` FOREIGN KEY (`EQUIPMENT_CD`) REFERENCES `MST_EQUIPMENT` (`EQUIPMENT_CD`),
  CONSTRAINT `FK_PLN_WO_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_PLN_WO_PLAN` FOREIGN KEY (`PLAN_ID`) REFERENCES `PLN_PROD_PLAN` (`PLAN_ID`),
  CONSTRAINT `FK_PLN_WO_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_PLN_WO_WC` FOREIGN KEY (`WORKCENTER_CD`) REFERENCES `MST_WORKCENTER` (`WORKCENTER_CD`),
  CONSTRAINT `FK_PLN_WO_WORKER` FOREIGN KEY (`WORKER_ID`) REFERENCES `MST_WORKER` (`WORKER_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='작업지시';
/*!40101 SET character_set_client = @saved_cs_client */;

