--
-- Table structure for table `PLN_WO_MATERIAL`
--

DROP TABLE IF EXISTS `PLN_WO_MATERIAL`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PLN_WO_MATERIAL` (
  `WO_MTL_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '자재ID',
  `WO_ID` bigint NOT NULL COMMENT '작업지시ID',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `PLAN_QTY` decimal(15,5) NOT NULL COMMENT '계획수량',
  `ISSUE_QTY` decimal(15,5) DEFAULT '0.00000' COMMENT '출고수량',
  `RETURN_QTY` decimal(15,5) DEFAULT '0.00000' COMMENT '반납수량',
  `LOSS_RATE` decimal(5,2) DEFAULT '0.00' COMMENT '손실율(%)',
  `WAREHOUSE_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '창고코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `MTL_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`WO_MTL_ID`),
  KEY `FK_PLN_WO_MTL_WO` (`WO_ID`),
  KEY `FK_PLN_WO_MTL_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_PLN_WO_MTL_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_PLN_WO_MTL_WO` FOREIGN KEY (`WO_ID`) REFERENCES `PLN_WORK_ORDER` (`WO_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='작업지시자재';
/*!40101 SET character_set_client = @saved_cs_client */;

