--
-- Table structure for table `PRD_DEFECT_HIS`
--

DROP TABLE IF EXISTS `PRD_DEFECT_HIS`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PRD_DEFECT_HIS` (
  `DEFECT_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '불량ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `RESULT_ID` bigint NOT NULL COMMENT '작업실적ID',
  `PROC_RESULT_ID` bigint DEFAULT NULL COMMENT '공정실적ID',
  `DEFECT_DT` date NOT NULL COMMENT '불량발생일',
  `DEFECT_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '불량유형',
  `DEFECT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '불량코드',
  `DEFECT_NM` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '불량명',
  `DEFECT_QTY` decimal(15,3) NOT NULL COMMENT '불량수량',
  `DEFECT_CAUSE` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '불량원인',
  `DEFECT_ACTION` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '조치내용',
  `DISPOSITION` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '처리방법',
  `DISPOSITION_QTY` decimal(15,3) DEFAULT NULL COMMENT '처리수량',
  `DISPOSITION_DT` date DEFAULT NULL COMMENT '처리일자',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `WORKER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '작업자ID',
  `EQUIPMENT_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '설비코드',
  `PROCESS_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '공정코드',
  `DEFECT_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`DEFECT_ID`),
  KEY `FK_PRD_DEFECT_PROC` (`PROC_RESULT_ID`),
  KEY `IDX_PRD_DEFECT_HIS_01` (`RESULT_ID`),
  KEY `IDX_PRD_DEFECT_HIS_02` (`PLANT_CD`,`DEFECT_DT`),
  KEY `IDX_PRD_DEFECT_HIS_03` (`DEFECT_CD`),
  KEY `IDX_PRD_DEFECT_HIS_04` (`ITEM_CD`,`LOT_NO`),
  CONSTRAINT `FK_PRD_DEFECT_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_PRD_DEFECT_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_PRD_DEFECT_PROC` FOREIGN KEY (`PROC_RESULT_ID`) REFERENCES `PRD_PROCESS_RESULT` (`PROC_RESULT_ID`),
  CONSTRAINT `FK_PRD_DEFECT_RESULT` FOREIGN KEY (`RESULT_ID`) REFERENCES `PRD_WORK_RESULT` (`RESULT_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='생산불량이력';
/*!40101 SET character_set_client = @saved_cs_client */;

