DROP TABLE IF EXISTS `PRD_MATERIAL_ISSUE`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PRD_MATERIAL_ISSUE` (
  `ISSUE_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '투입ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `RESULT_ID` bigint NOT NULL COMMENT '작업실적ID',
  `WO_ID` bigint NOT NULL COMMENT '작업지시ID',
  `ISSUE_DT` date NOT NULL COMMENT '투입일자',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `ISSUE_QTY` decimal(15,5) NOT NULL COMMENT '투입수량',
  `UNIT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '단위',
  `WAREHOUSE_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '창고코드',
  `LOCATION_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '로케이션',
  `ISSUE_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '정규투입' COMMENT '투입유형',
  `ISSUE_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`ISSUE_ID`),
  KEY `FK_PRD_ISSUE_PLANT` (`PLANT_CD`),
  KEY `IDX_PRD_MTL_ISSUE_01` (`RESULT_ID`),
  KEY `IDX_PRD_MTL_ISSUE_02` (`WO_ID`),
  KEY `IDX_PRD_MTL_ISSUE_03` (`ITEM_CD`,`LOT_NO`),
  CONSTRAINT `FK_PRD_ISSUE_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_PRD_ISSUE_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_PRD_ISSUE_RESULT` FOREIGN KEY (`RESULT_ID`) REFERENCES `PRD_WORK_RESULT` (`RESULT_ID`),
  CONSTRAINT `FK_PRD_ISSUE_WO` FOREIGN KEY (`WO_ID`) REFERENCES `PLN_WORK_ORDER` (`WO_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='자재투입이력';
