DROP TABLE IF EXISTS `QC_CALIBRATION_HIS`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `QC_CALIBRATION_HIS` (
  `CAL_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '교정ID',
  `MEASURE_EQUIP_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '측정장비코드',
  `CAL_DT` date NOT NULL COMMENT '교정일자',
  `CAL_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '교정유형',
  `CAL_AGENCY` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '교정기관',
  `CAL_RESULT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '교정결과',
  `CAL_CERT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '교정성적서번호',
  `BEFORE_VALUE` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '교정전값',
  `AFTER_VALUE` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '교정후값',
  `NEXT_CAL_DT` date DEFAULT NULL COMMENT '다음교정예정일',
  `CAL_COST` decimal(18,2) DEFAULT NULL COMMENT '교정비용',
  `CAL_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`CAL_ID`),
  KEY `IDX_QC_CAL_HIS_01` (`MEASURE_EQUIP_CD`,`CAL_DT`),
  CONSTRAINT `FK_QC_CAL_HIS_EQUIP` FOREIGN KEY (`MEASURE_EQUIP_CD`) REFERENCES `QC_MEASURE_EQUIP` (`MEASURE_EQUIP_CD`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='측정장비교정이력';
