DROP TABLE IF EXISTS `QC_COA`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `QC_COA` (
  `COA_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '성적서ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `COA_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '성적서번호',
  `COA_DT` date NOT NULL COMMENT '발행일자',
  `INSPECT_ID` bigint NOT NULL COMMENT '검사ID',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `SHIP_QTY` decimal(15,3) DEFAULT NULL COMMENT '출하수량',
  `CUSTOMER_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고객코드',
  `CUSTOMER_NM` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '고객명',
  `ORDER_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '주문번호',
  `ISSUE_USER_ID` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '발행자ID',
  `APPROVE_USER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '승인자ID',
  `APPROVE_DTM` datetime DEFAULT NULL COMMENT '승인일시',
  `COA_STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '발행' COMMENT '상태',
  `COA_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`COA_ID`),
  UNIQUE KEY `UK_QC_COA` (`COA_NO`),
  KEY `FK_QC_COA_ITEM` (`ITEM_CD`),
  KEY `IDX_QC_COA_01` (`PLANT_CD`,`COA_DT`),
  KEY `IDX_QC_COA_02` (`INSPECT_ID`),
  CONSTRAINT `FK_QC_COA_INSPECT` FOREIGN KEY (`INSPECT_ID`) REFERENCES `QC_INSPECT_RESULT` (`INSPECT_ID`),
  CONSTRAINT `FK_QC_COA_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_QC_COA_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='품질성적서';
