DROP TABLE IF EXISTS `QC_DEFECT_HIS`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `QC_DEFECT_HIS` (
  `QC_DEFECT_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '품질불량ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `INSPECT_ID` bigint NOT NULL COMMENT '검사ID',
  `DEFECT_DT` date NOT NULL COMMENT '불량발생일',
  `DEFECT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '불량코드',
  `DEFECT_NM` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '불량명',
  `DEFECT_QTY` decimal(15,3) NOT NULL COMMENT '불량수량',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `DEFECT_CAUSE` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '불량원인',
  `CAUSE_CATEGORY` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '원인구분(4M)',
  `CORRECTIVE_ACTION` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '시정조치',
  `PREVENTIVE_ACTION` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '예방조치',
  `ACTION_USER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '조치담당자',
  `ACTION_DT` date DEFAULT NULL COMMENT '조치일자',
  `DISPOSITION` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '처리방법',
  `DISPOSITION_QTY` decimal(15,3) DEFAULT NULL COMMENT '처리수량',
  `DISPOSITION_DT` date DEFAULT NULL COMMENT '처리일자',
  `DEFECT_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`QC_DEFECT_ID`),
  KEY `IDX_QC_DEFECT_HIS_01` (`PLANT_CD`,`DEFECT_DT`),
  KEY `IDX_QC_DEFECT_HIS_02` (`INSPECT_ID`),
  KEY `IDX_QC_DEFECT_HIS_03` (`DEFECT_CD`),
  KEY `IDX_QC_DEFECT_HIS_04` (`ITEM_CD`,`LOT_NO`),
  CONSTRAINT `FK_QC_DEFECT_HIS_CD` FOREIGN KEY (`DEFECT_CD`) REFERENCES `QC_DEFECT_CODE` (`DEFECT_CD`),
  CONSTRAINT `FK_QC_DEFECT_HIS_INSPECT` FOREIGN KEY (`INSPECT_ID`) REFERENCES `QC_INSPECT_RESULT` (`INSPECT_ID`),
  CONSTRAINT `FK_QC_DEFECT_HIS_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_QC_DEFECT_HIS_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='품질불량이력';
/*!40101 SET character_set_client = @saved_cs_client */;

