  `INSPECT_ID` bigint NOT NULL COMMENT '검사ID',
  `INSPECT_STD_ID` bigint NOT NULL COMMENT '검사기준ID',
  `SAMPLE_NO` int NOT NULL DEFAULT '1' COMMENT '샘플번호',
  `INSPECT_ITEM` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '검사항목',
  `DATA_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '데이터유형',
  `MEASURE_VALUE` decimal(15,5) DEFAULT NULL COMMENT '측정값(숫자)',
  `MEASURE_TEXT` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '측정값(텍스트)',
  `LSL` decimal(15,5) DEFAULT NULL COMMENT '하한규격',
  `USL` decimal(15,5) DEFAULT NULL COMMENT '상한규격',
  `TARGET_VALUE` decimal(15,5) DEFAULT NULL COMMENT '목표값',
  `JUDGE_RESULT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '판정결과',
  `DEFECT_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '불량코드',
  `DETAIL_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  PRIMARY KEY (`INSPECT_DTL_ID`),
  KEY `FK_QC_INSPECT_DTL_DEFECT` (`DEFECT_CD`),
  KEY `IDX_QC_INSPECT_DETAIL_01` (`INSPECT_ID`),
  KEY `IDX_QC_INSPECT_DETAIL_02` (`INSPECT_STD_ID`),
  CONSTRAINT `FK_QC_INSPECT_DTL_DEFECT` FOREIGN KEY (`DEFECT_CD`) REFERENCES `QC_DEFECT_CODE` (`DEFECT_CD`),
  CONSTRAINT `FK_QC_INSPECT_DTL_ID` FOREIGN KEY (`INSPECT_ID`) REFERENCES `QC_INSPECT_RESULT` (`INSPECT_ID`),
  CONSTRAINT `FK_QC_INSPECT_DTL_STD` FOREIGN KEY (`INSPECT_STD_ID`) REFERENCES `QC_INSPECT_STD` (`INSPECT_STD_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='검사상세';
