DROP TABLE IF EXISTS `QC_INSPECT_RESULT`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `QC_INSPECT_RESULT` (
  `INSPECT_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '검사ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `INSPECT_NO` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '검사번호',
  `INSPECT_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '검사유형',
  `INSPECT_DT` date NOT NULL COMMENT '검사일자',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `LOT_NO` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'LOT번호',
  `INSPECT_QTY` decimal(15,3) NOT NULL COMMENT '검사수량',
  `SAMPLE_QTY` decimal(15,3) DEFAULT NULL COMMENT '샘플수량',
  `PASS_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '합격수량',
  `FAIL_QTY` decimal(15,3) DEFAULT '0.000' COMMENT '불합격수량',
  `INSPECTOR_ID` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '검사자ID',
  `WO_ID` bigint DEFAULT NULL COMMENT '작업지시ID',
  `RESULT_ID` bigint DEFAULT NULL COMMENT '작업실적ID',
  `RECEIVE_ID` bigint DEFAULT NULL COMMENT '입고ID',
  `VENDOR_CD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '거래처코드',
  `JUDGE_RESULT` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '대기' COMMENT '판정결과',
  `JUDGE_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '판정자ID',
  `JUDGE_DTM` datetime DEFAULT NULL COMMENT '판정일시',
  `PROCESS_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '공정코드',
  `INSPECT_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`INSPECT_ID`),
  UNIQUE KEY `UK_QC_INSPECT_RESULT` (`INSPECT_NO`),
  KEY `FK_QC_INSPECT_INSPECTOR` (`INSPECTOR_ID`),
  KEY `IDX_QC_INSPECT_RESULT_01` (`PLANT_CD`,`INSPECT_DT`),
  KEY `IDX_QC_INSPECT_RESULT_02` (`ITEM_CD`,`LOT_NO`),
  KEY `IDX_QC_INSPECT_RESULT_03` (`INSPECT_TYPE`,`JUDGE_RESULT`),
  KEY `IDX_QC_INSPECT_RESULT_04` (`WO_ID`),
  KEY `IDX_QC_INSPECT_RESULT_05` (`VENDOR_CD`),
  CONSTRAINT `FK_QC_INSPECT_INSPECTOR` FOREIGN KEY (`INSPECTOR_ID`) REFERENCES `MST_WORKER` (`WORKER_ID`),
  CONSTRAINT `FK_QC_INSPECT_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_QC_INSPECT_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`),
  CONSTRAINT `FK_QC_INSPECT_VENDOR` FOREIGN KEY (`VENDOR_CD`) REFERENCES `MST_VENDOR` (`VENDOR_CD`),
  CONSTRAINT `FK_QC_INSPECT_WO` FOREIGN KEY (`WO_ID`) REFERENCES `PLN_WORK_ORDER` (`WO_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='검사실적';
/*!40101 SET character_set_client = @saved_cs_client */;

