CREATE TABLE `QC_INSPECT_STD` (
  `INSPECT_STD_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '검사기준ID',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `ITEM_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '품목코드',
  `INSPECT_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '검사유형',
  `INSPECT_ITEM_SEQ` int NOT NULL COMMENT '검사항목순서',
  `INSPECT_ITEM` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '검사항목',
  `INSPECT_METHOD` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '검사방법',
  `DATA_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'NUMBER' COMMENT '데이터유형',
  `SPEC_VALUE` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '규격값',
  `LSL` decimal(15,5) DEFAULT NULL COMMENT '하한규격',
  `USL` decimal(15,5) DEFAULT NULL COMMENT '상한규격',
  `TARGET_VALUE` decimal(15,5) DEFAULT NULL COMMENT '목표값',
  `UNIT` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '단위',
  `SAMPLE_SIZE` int DEFAULT '1' COMMENT '샘플크기',
  `SAMPLE_METHOD` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '샘플링방법',
  `INSPECT_TOOL` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '검사도구',
  `MANDATORY_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '필수여부',
  `PROCESS_CD` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '공정코드',
  `VALID_START_DT` date DEFAULT NULL COMMENT '유효시작일',
  `VALID_END_DT` date DEFAULT NULL COMMENT '유효종료일',
  `STD_RMK` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '사용여부',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`INSPECT_STD_ID`),
  UNIQUE KEY `UK_QC_INSPECT_STD` (`PLANT_CD`,`ITEM_CD`,`INSPECT_TYPE`,`INSPECT_ITEM_SEQ`),
  KEY `IDX_QC_INSPECT_STD_01` (`ITEM_CD`,`INSPECT_TYPE`),
  KEY `IDX_QC_INSPECT_STD_02` (`PLANT_CD`,`INSPECT_TYPE`),
  CONSTRAINT `FK_QC_INSPECT_STD_ITEM` FOREIGN KEY (`ITEM_CD`) REFERENCES `MST_ITEM` (`ITEM_CD`),
  CONSTRAINT `FK_QC_INSPECT_STD_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='검사기준';
