--
-- Table structure for table `QC_MEASURE_EQUIP`
--

DROP TABLE IF EXISTS `QC_MEASURE_EQUIP`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `QC_MEASURE_EQUIP` (
  `MEASURE_EQUIP_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '측정장비코드',
  `PLANT_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '공장코드',
  `MEASURE_EQUIP_NM` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '측정장비명',
  `EQUIP_TYPE` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '장비유형',
  `MODEL_NM` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '모델명',
  `MAKER` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '제조사',
  `SERIAL_NO` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '시리얼번호',
  `MEASURE_RANGE` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '측정범위',
  `RESOLUTION` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '분해능',
  `ACCURACY` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '정확도',
  `PURCHASE_DT` date DEFAULT NULL COMMENT '구매일',
  `LAST_CAL_DT` date DEFAULT NULL COMMENT '최종교정일',
  `NEXT_CAL_DT` date DEFAULT NULL COMMENT '다음교정예정일',
  `CAL_CYCLE` int DEFAULT NULL COMMENT '교정주기(월)',
  `LOCATION` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '보관위치',
  `MANAGER_ID` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '담당자ID',
  `EQUIP_STATUS` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT '정상' COMMENT '장비상태',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Y' COMMENT '사용여부',
  `REG_USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '등록자ID',
  `REG_DTM` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_USER_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  `UPD_DTM` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`MEASURE_EQUIP_CD`),
  KEY `IDX_QC_MEASURE_EQUIP_01` (`PLANT_CD`,`EQUIP_STATUS`),
  KEY `IDX_QC_MEASURE_EQUIP_02` (`NEXT_CAL_DT`),
  CONSTRAINT `FK_QC_MEASURE_EQUIP_PLANT` FOREIGN KEY (`PLANT_CD`) REFERENCES `MST_PLANT` (`PLANT_CD`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='측정장비';
/*!40101 SET character_set_client = @saved_cs_client */;

