/*!50003 SET sql_mode              = 'REAL_AS_FLOAT,PIPES_AS_CONCAT,ANSI_QUOTES,IGNORE_SPACE,ONLY_FULL_GROUP_BY,ANSI,STRICT_TRANS_TABLES,STRICT_ALL_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER="avnadmin"@"%" PROCEDURE "SP_START_WORK_ORDER"(
    IN p_wo_id BIGINT,
    IN p_worker_id VARCHAR(20),
    IN p_equipment_cd VARCHAR(20),
    IN p_user_id VARCHAR(50)
)
BEGIN
    -- 작업지시 상태 변경
    UPDATE PLN_WORK_ORDER
    SET WO_STATUS = '진행',
        ACTUAL_START_DTM = NOW(),
        WORKER_ID = p_worker_id,
        EQUIPMENT_CD = p_equipment_cd,
        UPD_USER_ID = p_user_id,
        UPD_DTM = NOW()
    WHERE WO_ID = p_wo_id;
    
    -- 설비 가동 시작 기록
    IF p_equipment_cd IS NOT NULL THEN
        INSERT INTO EQP_OPER_STATUS (
            PLANT_CD, EQUIPMENT_CD, OPER_DT, SHIFT, OPER_STATUS,
            START_DTM, WO_ID, WORKER_ID, REG_USER_ID
        )
        SELECT PLANT_CD, p_equipment_cd, CURDATE(), 
               CASE WHEN HOUR(NOW()) < 18 THEN '주간' ELSE '야간' END,
               '가동', NOW(), p_wo_id, p_worker_id, p_user_id
        FROM PLN_WORK_ORDER
        WHERE WO_ID = p_wo_id;
    END IF;
END ;;
DELIMITER ;
